import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Profile({ token, user }) {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({});

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      const res = await axios.get('/api/users/profile', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProfile(res.data);
      setFormData(res.data);
    } catch (err) {
      setError('Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleSave = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.put('/api/users/profile', formData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProfile(res.data);
      setSuccess('Profile updated successfully!');
      setIsEditing(false);
      setTimeout(() => setSuccess(''), 2000);
    } catch (err) {
      setError('Failed to update profile');
    }
  };

  if (loading) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif' }}>Loading profile...</div>;
  if (error) return <div style={{ padding: '60px 50px', textAlign: 'center', fontFamily: 'Helvetica, Arial, sans-serif', color: '#d32f2f' }}>{error}</div>;

  const inputStyle = {
    width: '100%',
    padding: '12px 10px',
    border: '1px solid #f0f0f0',
    fontSize: '13px',
    fontFamily: 'Helvetica, Arial, sans-serif',
    color: '#000',
    boxSizing: 'border-box'
  };

  const labelStyle = {
    display: 'block',
    fontSize: '11px',
    fontWeight: '400',
    letterSpacing: '0.5px',
    textTransform: 'uppercase',
    color: '#999',
    marginBottom: '8px'
  };

  return (
    <div style={{
      padding: '60px 50px',
      backgroundColor: '#fff',
      fontFamily: 'Helvetica, Arial, sans-serif'
    }}>
      <h1 style={{
        fontSize: '28px',
        fontWeight: '300',
        letterSpacing: '1px',
        color: '#000',
        margin: '0 0 40px 0',
        textTransform: 'uppercase'
      }}>
        MY ACCOUNT
      </h1>

      {success && (
        <div style={{
          padding: '12px',
          backgroundColor: '#f0f0f0',
          color: '#000',
          fontSize: '12px',
          marginBottom: '30px',
          letterSpacing: '0.5px'
        }}>
          {success}
        </div>
      )}

      {!isEditing ? (
        <div style={{ maxWidth: '500px' }}>
          <div style={{
            paddingBottom: '20px',
            marginBottom: '20px',
            borderBottom: '1px solid #f0f0f0'
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: '#999',
              margin: '0 0 8px 0'
            }}>
              NAME
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: '#000',
              margin: '0'
            }}>
              {profile?.name}
            </p>
          </div>

          <div style={{
            paddingBottom: '20px',
            marginBottom: '20px',
            borderBottom: '1px solid #f0f0f0'
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: '#999',
              margin: '0 0 8px 0'
            }}>
              EMAIL
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: '#000',
              margin: '0'
            }}>
              {profile?.email}
            </p>
          </div>

          <div style={{
            paddingBottom: '20px',
            marginBottom: '20px',
            borderBottom: '1px solid #f0f0f0'
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: '#999',
              margin: '0 0 8px 0'
            }}>
              PHONE
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: '#000',
              margin: '0'
            }}>
              {profile?.phone || 'Not provided'}
            </p>
          </div>

          <div style={{
            paddingBottom: '20px',
            marginBottom: '30px',
            borderBottom: '1px solid #f0f0f0'
          }}>
            <p style={{
              fontSize: '11px',
              fontWeight: '400',
              letterSpacing: '0.5px',
              textTransform: 'uppercase',
              color: '#999',
              margin: '0 0 8px 0'
            }}>
              ADDRESS
            </p>
            <p style={{
              fontSize: '13px',
              fontWeight: '300',
              color: '#000',
              margin: '0',
              lineHeight: '1.6'
            }}>
              {profile?.address || 'Not provided'}
            </p>
          </div>

          <button
            onClick={() => setIsEditing(true)}
            style={{
              padding: '15px 40px',
              backgroundColor: '#000',
              color: '#fff',
              border: 'none',
              fontSize: '12px',
              fontFamily: 'Helvetica, Arial, sans-serif',
              fontWeight: '400',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              cursor: 'pointer',
              transition: 'opacity 0.3s'
            }}
            onMouseEnter={(e) => e.target.style.opacity = '0.8'}
            onMouseLeave={(e) => e.target.style.opacity = '1'}
          >
            EDIT PROFILE
          </button>
        </div>
      ) : (
        <form onSubmit={handleSave} style={{ maxWidth: '500px' }}>
          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Name</label>
            <input
              type="text"
              value={formData.name || ''}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Email</label>
            <input
              type="email"
              value={formData.email || ''}
              disabled
              style={{
                ...inputStyle,
                backgroundColor: '#f9f9f9',
                color: '#999'
              }}
            />
          </div>

          <div style={{ marginBottom: '20px' }}>
            <label style={labelStyle}>Phone</label>
            <input
              type="tel"
              value={formData.phone || ''}
              onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
              style={inputStyle}
            />
          </div>

          <div style={{ marginBottom: '30px' }}>
            <label style={labelStyle}>Address</label>
            <textarea
              value={formData.address || ''}
              onChange={(e) => setFormData({ ...formData, address: e.target.value })}
              rows="4"
              style={{
                ...inputStyle,
                resize: 'vertical'
              }}
            />
          </div>

          <div style={{ display: 'flex', gap: '15px' }}>
            <button
              type="submit"
              style={{
                padding: '15px 40px',
                backgroundColor: '#000',
                color: '#fff',
                border: 'none',
                fontSize: '12px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: '400',
                letterSpacing: '1px',
                textTransform: 'uppercase',
                cursor: 'pointer',
                transition: 'opacity 0.3s'
              }}
              onMouseEnter={(e) => e.target.style.opacity = '0.8'}
              onMouseLeave={(e) => e.target.style.opacity = '1'}
            >
              SAVE CHANGES
            </button>
            <button
              type="button"
              onClick={() => setIsEditing(false)}
              style={{
                padding: '15px 40px',
                backgroundColor: '#fff',
                color: '#000',
                border: '1px solid #f0f0f0',
                fontSize: '12px',
                fontFamily: 'Helvetica, Arial, sans-serif',
                fontWeight: '400',
                letterSpacing: '1px',
                textTransform: 'uppercase',
                cursor: 'pointer',
                transition: 'all 0.3s'
              }}
              onMouseEnter={(e) => {
                e.target.style.border = '1px solid #000';
              }}
              onMouseLeave={(e) => {
                e.target.style.border = '1px solid #f0f0f0';
              }}
            >
              CANCEL
            </button>
          </div>
        </form>
      )}
    </div>
  );
}

export default Profile;
